code.C:
#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long k;
        scanf("%lld", &k);
        long long n = 0;
        for (int i = 1; i < k; i++) {
            n = n * 10 + 9;
        }
        printf("%lld\n", n);
    }
    return 0;
}

